import React, { Children, useState } from 'react';
import { FlatList } from 'react-native';

import {
  isAllowedComponent,
  isReactElement,
} from '../../../utils/validadetype';
import { Box } from '../../atoms/Box';
import { SeparatorHorizontal } from '../../atoms/Spacing';
import useCardOptionDrag from './index';
import { PropsCardOptionDragGroup } from './Models';
import { CardOptionDrag } from './view';

function CardOptionDragGroup({
  mt,
  mb,
  ml,
  mr,
  testID,
  children,
  refComponent,
  disabled,
  openedIndex,
  onPress,
  onMomentumScrollBegin,
  onMomentumScrollEnd,
  onScrollBeginDrag,
  onScrollEndDrag,
  onEndReached,
  onEndReachedThreshold,
  ListFooterComponent,
}: PropsCardOptionDragGroup) {
  const [scrollEnabled, setScrollEnabled] = useState(true);
  const { cloneWithProps } = useCardOptionDrag({ children });
  const clonedChildren = cloneWithProps(children, {
    onPress,
    disabled,
  });

  const itemSeparator = () => {
    return (
      <SeparatorHorizontal
        width="100%"
        height={1}
        bgColor="BRAND_COMPLEMENT_02"
      />
    );
  };

  return (
    <Box testID={testID} width="100%" mt={mt} mb={mb} ml={ml} mr={mr}>
      <FlatList
        ref={refComponent}
        onMomentumScrollBegin={onMomentumScrollBegin}
        onMomentumScrollEnd={onMomentumScrollEnd}
        onScrollBeginDrag={onScrollBeginDrag}
        onScrollEndDrag={onScrollEndDrag}
        onEndReached={onEndReached}
        scrollEnabled={scrollEnabled}
        onEndReachedThreshold={onEndReachedThreshold}
        ListFooterComponent={ListFooterComponent}
        data={Children.toArray(clonedChildren)}
        showsVerticalScrollIndicator={false}
        ItemSeparatorComponent={itemSeparator}
        contentContainerStyle={{
          width: '100%',
        }}
        renderItem={({ item, index }) =>
          isReactElement(item) &&
          isAllowedComponent(
            (item.type as unknown as { displayName: string }).displayName,
            'CardOptionDragComponent',
          ) ? (
            <Box width="100%" key={index.valueOf()} direction>
              <CardOptionDrag
                {...item.props}
                closeCard={openedIndex !== index}
                isMoving={(value) => setScrollEnabled(!value)}
              />
            </Box>
          ) : null
        }
      />
    </Box>
  );
}

export default CardOptionDragGroup;

